// MARK: - Services

class API {
    private var URLSession = URLSession.shared
    
    func fetchStockData(symbol: String) -> AnyPublisher<Data, Error> {
        guard let url = URL(string: "https://api.example.com/stock/\(symbol)") else { return Fail(error: NSError(domain: "Invalid URL", code: 1)).eraseToAnyPublisher() }
        
        return URLSession.dataTaskPublisher(for: url)
            .map(\.data)
            .eraseToAnyPublisher()
    }
    
    func executeOrder(trade: Trade) -> AnyPublisher<Data, Error> {
        guard let url = URL(string: "https://api.example.com/order") else { return Fail(error: NSError(domain: "Invalid URL", code: 1)).eraseToAnyPublisher() }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let encoder = JSONEncoder()
        if let tradeData = try? encoder.encode(trade) {
            request.httpBody = tradeData
        }
        
        return URLSession.dataTaskPublisher(for: request)
            .map(\.data)
            .eraseToAnyPublisher()
    }
}

